import { useState } from "react";
import { getWeather } from "../services/weatherAPI";

function Chatbot() {

    const [message, setMessage] = useState("");
    const [chat, setChat] = useState([]);

    const handleSend = async () => {

        if (!message.trim()) return;

        const userMsg = { sender: "user", text: message };

        setChat(prev => [...prev, userMsg]);

        const text = message.toLowerCase();

        const cityList = [
            "chennai",
            "coimbatore",
            "madurai",
            "salem",
            "trichy",
            "erode",
            "tirunelveli",
            "delhi",
            "mumbai",
            "bangalore",
            "hyderabad"
        ];

        let city = null;

        for (let c of cityList) {
            if (text.includes(c)) {
                city = c;
                break;
            }
        }

        if (!city) {
            setChat(prev => [...prev, { sender: "bot", text: "City not found." }]);
            return;
        }

        const weather = await getWeather(city);

        let botReply;

        if (weather) {
            botReply = {
                sender: "bot",
                text: `Temperature in ${city} is ${weather.temperature}°C and wind speed is ${weather.windspeed} km/h`
            };
        } else {
            botReply = {
                sender: "bot",
                text: "City not found."
            };
        }

        setChat(prev => [...prev, userMsg, botReply]);

        setMessage("");
    };

    return (

        <div style={{ maxWidth: "600px", margin: "auto" }}>

            <h1 style={{ textAlign: "center" }}>AI Climate Chatbot</h1>

            {/* Chat Area */}

            <div style={{
                height: "400px",
                border: "1px solid #444",
                padding: "10px",
                overflowY: "auto",
                marginBottom: "10px"
            }}>

                {chat.map((msg, index) => (

                    <div
                        key={index}
                        style={{
                            textAlign: msg.sender === "user" ? "right" : "left",
                            margin: "10px 0"
                        }}
                    >

                        <span
                            style={{
                                display: "inline-block",
                                padding: "10px",
                                borderRadius: "10px",
                                background: msg.sender === "user" ? "#4CAF50" : "#333",
                                color: "white",
                                maxWidth: "70%"
                            }}
                        >
                            {msg.text}
                        </span>

                    </div>

                ))}

            </div>

            {/* Input */}

            <div style={{ display: "flex", gap: "10px" }}>

                <input
                    style={{ flex: 1, padding: "10px" }}
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    placeholder="Ask climate question..."
                />

                <button onClick={handleSend}>Send</button>

            </div>

        </div>

    );
}

export default Chatbot;
